// Converts a hexadecimal string to an unsigned 32-bit integer.
uint32_t strtoul_hex(const char *str)
{
    uint32_t res = 0;
    // Skip optional "0x" prefix
    if (str[0] == '0' && (str[1] == 'x' || str[1] == 'X'))
    {
        str += 2;
    }
    while (*str)
    {
        uint8_t digit;
        if (*str >= '0' && *str <= '9')
        {
            digit = *str - '0';
        }
        else if (*str >= 'a' && *str <= 'f')
        {
            digit = *str - 'a' + 10;
        }
        else if (*str >= 'A' && *str <= 'F')
        {
            digit = *str - 'A' + 10;
        }
        else
        {
            break; // Invalid character
        }
        res = (res << 4) | digit;
        str++;
    }
    return res;
}

// Converts a decimal string to an unsigned 32-bit integer.
uint32_t strtoul_dec(const char *str)
{
    uint32_t res = 0;
    while (*str >= '0' && *str <= '9')
    {
        res = res * 10 + (*str - '0');
        str++;
    }
    return res;
}

