// --- Debug Shell Implementation ---

#define MAX_COMMAND_LENGTH 64
static char command_buffer[MAX_COMMAND_LENGTH];
static uint8_t command_idx = 0;

// Prints the shell prompt.
void print_prompt(void)
{
    print_str("shell> ");
}

// Processes the received command from the shell buffer.
void process_command(void)
{
    command_buffer[command_idx] = '\0'; // Null-terminate the command string

    char *cmd = command_buffer;
    char *args = NULL;

    // Find the first space to separate the command from its arguments.
    for (uint8_t i = 0; i < command_idx; ++i)
    {
        if (command_buffer[i] == ' ')
        {
            command_buffer[i] = '\0';     // Null-terminate the command part
            args = &command_buffer[i+1];  // Arguments start after the space
            // Skip any leading spaces in the arguments string
            while (*args == ' ') args++;
            if (*args == '\0') args = NULL; // No actual arguments if only spaces followed
            break;
        }
    }

    if (streq(cmd, "dump_memory"))
    {
        handle_dump_memory(args);
    }
    else if (streq(cmd, "read_flash"))
    {
        handle_read_flash(args);
    }
    else if (streq(cmd, "get_config"))
    {
        handle_get_config(args);
    }
    else if (streq(cmd, "help"))
    {
        print_str("Available commands:");
        print_newline();
        print_str("  dump_memory <start_addr_hex> <length_hex/dec> - Dumps memory region.");
        print_newline();
        print_str("  read_flash <start_addr_hex> <length_hex/dec> - Reads flash memory region.");
        print_newline();
        print_str("  get_config - Displays system configuration.");
        print_newline();
        print_str("  help - Display this help message.");
        print_newline();
    }
    else if (cmd[0] != '\0') // If command is not empty but also not recognized
    {
        print_str("Unknown command: ");
        print_str(cmd);
        print_newline();
    }

    command_idx = 0; // Reset the command buffer index for the next command
}

// Main loop for the debug shell. Should be called periodically.
void debug_shell_run(void)
{
    char c = uart_rx_char(); // Blocks until a character is received

    if (c == '\r' || c == '\n') // Command termination (Enter key)
    {
        uart_tx_char('\r'); // Echo newline sequence for cleaner terminal output
        uart_tx_char('\n');
        process_command();
        print_prompt(); // Show prompt for next command
    }
    else if (c == 8 || c == 127) // Backspace or Delete key
    {
        if (command_idx > 0)
        {
            command_idx--;
            uart_tx_char(8);   // Move cursor back
            uart_tx_char(' '); // Overwrite the character with a space
            uart_tx_char(8);   // Move cursor back again
        }
    }
    else if (command_idx < (MAX_COMMAND_LENGTH - 1)) // Store character if buffer has space
    {
        command_buffer[command_idx++] = c;
        uart_tx_char(c); // Echo character back to the terminal
    }
    // Ignore character if buffer is full
}

